//! `Lazy` primitive — wasm code-splitting boundaries.
//!
//! Declares a point in the UI tree where the subtree below is
//! shipped as a separate wasm chunk (web) or compiled inline
//! (native). The chunk loads on first mount; the author observes
//! lifecycle via the `on_state` callback and a placeholder
//! primitive is shown during the load.
//!
//! See `docs/proposals/lazy-primitive.md` for the full design.
//!
//! # Author API
//!
//! ```ignore
//! use runtime_core::primitives::lazy::{lazy, LazyState};
//! use simulator_chunk::SimulatorProps;
//! use crate::chunks;  // generated by `runtime_core::chunks!()`
//!
//! ui! {
//!     Lazy::<SimulatorProps>(chunks::SIMULATOR, SimulatorProps {
//!         skin: SkinKind::Ios,
//!     })
//!     .on_state(move |s| state_signal.set(s))
//!     .placeholder(|| ui! { Spinner {} })
//! }
//! ```
//!
//! # Status
//!
//! PR 1 only ships the type surface — primitive variant, constructor,
//! `LazyState`, `ChunkId`, `LazyBridge`, `LazyRegistry`. Backend
//! handlers ship in subsequent PRs:
//!
//! - PR 3: native handler (uses `LazyRegistry` impls).
//! - PR 6: web handler (dynamic `import()` + `mount_chunk` lifecycle).
//!
//! Until those land, a `Primitive::Lazy` mounts its placeholder and
//! fires `LazyState::Loading` once; the chunk never actually loads.
//! This is intentional — code that uses `lazy()` today will be
//! ready when the lifecycle wires up, without API churn.

use crate::accessibility::AccessibilityProps;
use crate::builder::IntoPrimitive;
use crate::handles::RefFill;
use crate::primitive::Primitive;
use crate::sources::{IntoStyleSource, StyleSource};
use std::any::{Any, TypeId};
use std::cell::RefCell;
use std::collections::HashMap;
use std::marker::PhantomData;
use std::rc::Rc;

// ---------------------------------------------------------------------------
// ChunkId — compile-time-checked identifier for a declared chunk.
// ---------------------------------------------------------------------------

/// Identifier for a lazy chunk. Author code should never construct
/// these directly — the `runtime_core::chunks!()` proc macro (PR 2)
/// emits typed constants from the project's
/// `[package.metadata.idealyst.chunks]` manifest entries, and author
/// code references those constants (e.g. `chunks::SIMULATOR`). That
/// makes typos a compile error instead of a runtime panic.
///
/// `ChunkId` is a `&'static str` newtype because the underlying
/// representation needs to round-trip through the manifest (which
/// stringly-names chunks), through the wire protocol on web (where
/// chunk URLs are looked up by name), and through the native
/// `LazyRegistry` (keyed by chunk identifier). `&'static str` is
/// the only representation that satisfies all three without
/// per-call allocation.
#[derive(Clone, Copy, PartialEq, Eq, Hash, Debug)]
pub struct ChunkId(&'static str);

impl ChunkId {
    /// Construct a `ChunkId` from a static string. Intended for use
    /// by the codegen'd `chunks::*` constants and tests; author code
    /// outside the framework should reference the generated
    /// constants instead.
    pub const fn new(name: &'static str) -> Self {
        Self(name)
    }

    /// The underlying chunk name as it appears in the manifest.
    pub const fn as_str(self) -> &'static str {
        self.0
    }
}

impl std::fmt::Display for ChunkId {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(self.0)
    }
}

// ---------------------------------------------------------------------------
// LazyState — lifecycle observable to author code via on_state.
// ---------------------------------------------------------------------------

/// Lifecycle phases of a `Primitive::Lazy`. Author code subscribes
/// via [`LazyBuilder::on_state`] to render its own loading / error
/// UI; the framework also mounts the [placeholder](LazyBuilder::placeholder)
/// during `Loading` / `Loaded` as an immediate fallback.
///
/// On native targets the chunk is compiled in and rendered inline —
/// the callback fires once with [`Rendered`](Self::Rendered) and
/// never observes [`Loading`](Self::Loading) or [`Loaded`](Self::Loaded).
#[derive(Clone, Debug)]
pub enum LazyState {
    /// Chunk fetch in flight. Web only — never observed on native.
    Loading,
    /// Chunk module fetched and instantiated; mount call hasn't
    /// returned yet. A brief window; many authors won't bother
    /// distinguishing this from `Loading`.
    Loaded,
    /// Chunk's `mount_chunk` returned successfully; the chunk's UI
    /// has taken over the placeholder's DOM subtree (web) or has
    /// been built inline (native).
    Rendered,
    /// Fetch or mount failed. The string is the underlying error,
    /// suitable for logging. Author decides whether to retry, fall
    /// back permanently, or surface to the user.
    Error(String),
}

impl LazyState {
    /// Convenience predicate for "show the placeholder" UI states.
    pub fn is_loading(&self) -> bool {
        matches!(self, LazyState::Loading | LazyState::Loaded)
    }

    /// Convenience predicate for "load failed" UI state.
    pub fn is_error(&self) -> bool {
        matches!(self, LazyState::Error(_))
    }
}

// ---------------------------------------------------------------------------
// LazyBridge — codegen'd serialize + thunk helpers.
// ---------------------------------------------------------------------------

/// Per-instance helpers that bridge the type-erased
/// [`Primitive::Lazy::payload`] back into something the active
/// backend can act on. Constructed inside [`lazy::<T>`](lazy)
/// from the generic `T`'s `Serialize` impl; the framework never
/// inspects `T` directly.
///
/// - `serialize` is used by the web backend (PR 6) to JSON-encode
///   the props for transport to the chunk's `mount_chunk` /
///   `update_chunk` exports.
/// - `clone_payload` is used by the native backend (PR 3) to hand
///   a fresh `Rc<dyn Any>` to the registered chunk thunk without
///   forcing `Clone` onto the lazy primitive itself.
///
/// Boxed closures rather than trait objects on `T` so the
/// `Primitive::Lazy` variant doesn't need a generic parameter
/// (which would prevent it from being a plain enum variant).
pub struct LazyBridge {
    /// JSON-serialize the type-erased payload. Returns the JSON
    /// string on success, or a human-readable error message on
    /// failure (mismatched downcast, serde error, etc.).
    pub serialize: Box<dyn Fn(&dyn Any) -> Result<String, String>>,
}

// ---------------------------------------------------------------------------
// LazyRegistry — backend trait for native chunk dispatch (PR 3).
// ---------------------------------------------------------------------------

/// Trait backends implement to receive registrations from a project's
/// codegen'd `chunks::register(&mut backend)` call. On non-wasm
/// targets the registered thunk is invoked when a `Primitive::Lazy`
/// mounts, and its returned `Primitive` is rendered inline. On web
/// the registry is unused — chunks load dynamically.
///
/// Native backends should store registrations in a map keyed by
/// [`ChunkId`]. The thunk takes the type-erased payload (a
/// `Rc<dyn Any>` pointing at the props the author passed) and is
/// expected to downcast it to the concrete props type for the
/// chunk crate's `app(props)` signature.
///
/// `'static` bound on the thunk because it has to live alongside
/// the backend; in practice this is fine — the codegen'd thunk
/// captures nothing beyond the chunk crate's `app` fn pointer.
pub trait LazyRegistry {
    /// Register a native-side dispatch thunk for `chunk`. Calling
    /// `register_lazy` twice with the same `ChunkId` replaces the
    /// prior thunk; backends should not error on re-registration
    /// (hot reload paths re-run the bootstrap).
    fn register_lazy(
        &mut self,
        chunk: ChunkId,
        thunk: Box<dyn Fn(Rc<dyn Any>) -> Primitive + 'static>,
    );
}

// ---------------------------------------------------------------------------
// Thread-local chunk registry — process-global on native.
// ---------------------------------------------------------------------------
//
// PR 3 will likely move this to per-backend registries (so a test
// harness can mount multiple isolated backends with distinct chunk
// sets), but for v1 a thread-local global mirrors how the existing
// `ambient_navigator()` and theme registry work — single-threaded
// runtime, one chunk universe per process. Callers should treat
// the registry as **append-only at boot**: register every chunk
// before the first `Primitive::Lazy` mounts.

thread_local! {
    static LAZY_REGISTRY: RefCell<HashMap<ChunkId, Rc<dyn Fn(Rc<dyn Any>) -> Primitive>>> =
        RefCell::new(HashMap::new());
}

/// Register a chunk's native dispatch thunk. On non-wasm targets the
/// framework's walker uses this to render `Primitive::Lazy` inline
/// (chunks compile in as normal cargo deps). On wasm the registry
/// is unused — chunks load dynamically via the web backend handler
/// (PR 6).
///
/// Registration is keyed by [`ChunkId`]; calling twice with the
/// same chunk replaces the prior thunk. Most apps register once at
/// startup via the codegen'd `chunks::register()` (PR 2); manual
/// registration is fine for tests and exploratory demos.
///
/// The thunk receives the type-erased payload (props the author
/// passed to `lazy(chunk, props)`) and should downcast to the
/// chunk crate's concrete props type before calling its `app(props)`.
pub fn register(
    chunk: ChunkId,
    thunk: impl Fn(Rc<dyn Any>) -> Primitive + 'static,
) {
    LAZY_REGISTRY.with(|r| {
        r.borrow_mut().insert(chunk, Rc::new(thunk));
    });
}

/// Look up a chunk's registered thunk and invoke it with `payload`.
/// Returns the chunk's `Primitive` for the walker to mount inline,
/// or `None` if no thunk is registered. Walker-internal.
pub(crate) fn dispatch(chunk: ChunkId, payload: Rc<dyn Any>) -> Option<Primitive> {
    LAZY_REGISTRY.with(|r| {
        r.borrow().get(&chunk).map(|thunk| {
            let f = thunk.clone();
            f(payload)
        })
    })
}

/// Clear the registry. Test-only — production code should never
/// need to unregister chunks during a session.
#[cfg(any(test, debug_assertions))]
pub fn clear_registry() {
    LAZY_REGISTRY.with(|r| r.borrow_mut().clear());
}

// ---------------------------------------------------------------------------
// LazyBuilder + lazy() constructor — author surface.
// ---------------------------------------------------------------------------

/// Builder produced by [`lazy::<T>`](lazy). Use `.on_state(...)`,
/// `.placeholder(...)`, and `.with_style(...)` to configure, then
/// drop into a `ui!` block or call `.into_primitive()`.
///
/// Reasonable defaults: no state observer, no placeholder (empty
/// view rendered during load), no style.
pub struct LazyBuilder<T: 'static> {
    chunk: ChunkId,
    payload: Rc<T>,
    on_state: Option<Rc<dyn Fn(LazyState)>>,
    placeholder: Option<Box<dyn Fn() -> Primitive>>,
    style: Option<StyleSource>,
    ref_fill: Option<RefFill>,
    accessibility: AccessibilityProps,
    _t: PhantomData<T>,
}

impl<T> LazyBuilder<T>
where
    T: serde::Serialize + 'static,
{
    /// Subscribe to lifecycle transitions. Fires synchronously on
    /// each state change; the callback should be cheap (typically
    /// a single `Signal::set`). Use this to drive a placeholder /
    /// error UI elsewhere in the tree.
    pub fn on_state<F>(mut self, f: F) -> Self
    where
        F: Fn(LazyState) + 'static,
    {
        self.on_state = Some(Rc::new(f));
        self
    }

    /// Set the placeholder rendered while the chunk loads. On native
    /// the placeholder is never visible (the chunk mounts
    /// synchronously); on web it's mounted immediately and replaced
    /// when the chunk's `mount_chunk` returns. Default: nothing
    /// (an empty view).
    pub fn placeholder<F>(mut self, build: F) -> Self
    where
        F: Fn() -> Primitive + 'static,
    {
        self.placeholder = Some(Box::new(build));
        self
    }

    /// Attach a style to the lazy primitive's container (the
    /// placeholder's wrapping view on web, the rendered subtree's
    /// root on native).
    pub fn with_style<S: IntoStyleSource>(mut self, style: S) -> Self {
        self.style = Some(style.into_style_source());
        self
    }

    /// Attach accessibility props to the container.
    pub fn with_accessibility(mut self, a11y: AccessibilityProps) -> Self {
        self.accessibility = a11y;
        self
    }
}

impl<T> IntoPrimitive for LazyBuilder<T>
where
    T: serde::Serialize + 'static,
{
    fn into_primitive(self) -> Primitive {
        // The payload starts as `Rc<T>` so we can keep `T` accessible
        // for the serialize closure; we coerce to `Rc<dyn Any>` for
        // the variant slot. The serializer downcasts back to `T`.
        let payload_any: Rc<dyn Any> = self.payload;
        let bridge = LazyBridge {
            serialize: Box::new(|payload: &dyn Any| -> Result<String, String> {
                let typed = payload.downcast_ref::<T>().ok_or_else(|| {
                    format!(
                        "LazyBridge::serialize: payload downcast to {} failed",
                        std::any::type_name::<T>(),
                    )
                })?;
                crate::__serde_json::to_string(typed).map_err(|e| e.to_string())
            }),
        };
        Primitive::Lazy {
            chunk: self.chunk,
            type_id: TypeId::of::<T>(),
            type_name: std::any::type_name::<T>(),
            payload: payload_any,
            bridge,
            on_state: self.on_state,
            placeholder: self.placeholder,
            style: self.style,
            ref_fill: self.ref_fill,
            accessibility: self.accessibility,
        }
    }
}

/// Construct a lazy chunk boundary. `T` is the chunk crate's
/// `app(props)` parameter type — the framework type-erases it
/// here and the backend handler re-materializes it on the other
/// side (via serde on web, via the registered thunk on native).
///
/// `T: Serialize` is required because props cross a wasm boundary
/// on web. On native the bound is harmless — serde-able types are
/// also plain Rust types.
///
/// See module docs for the full author API.
pub fn lazy<T>(chunk: ChunkId, props: T) -> LazyBuilder<T>
where
    T: serde::Serialize + 'static,
{
    LazyBuilder {
        chunk,
        payload: Rc::new(props),
        on_state: None,
        placeholder: None,
        style: None,
        ref_fill: None,
        accessibility: AccessibilityProps::default(),
        _t: PhantomData,
    }
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;
    use serde::Serialize;

    #[derive(Serialize, Clone)]
    struct DemoProps {
        skin: String,
        device: u32,
    }

    const DEMO: ChunkId = ChunkId::new("demo");

    #[test]
    fn constructor_emits_lazy_variant() {
        let p = lazy::<DemoProps>(
            DEMO,
            DemoProps {
                skin: "ios".to_string(),
                device: 14,
            },
        )
        .into_primitive();

        match p {
            Primitive::Lazy {
                chunk,
                type_id,
                type_name,
                ..
            } => {
                assert_eq!(chunk, DEMO);
                assert_eq!(type_id, TypeId::of::<DemoProps>());
                assert!(
                    type_name.contains("DemoProps"),
                    "type_name should mention DemoProps, got {type_name}",
                );
            }
            _ => panic!("expected Primitive::Lazy"),
        }
    }

    #[test]
    fn bridge_round_trips_props_through_json() {
        // The bridge must serialize the type-erased payload back to
        // the JSON the web `mount_chunk` will deserialize on the
        // other side. A failing round-trip here means the chunk
        // would receive corrupt / empty props at runtime.
        let p = lazy::<DemoProps>(
            DEMO,
            DemoProps {
                skin: "android".to_string(),
                device: 7,
            },
        )
        .into_primitive();

        let Primitive::Lazy {
            payload, bridge, ..
        } = p
        else {
            panic!("expected Primitive::Lazy");
        };

        let json = (bridge.serialize)(&*payload).expect("serialize");
        let parsed: serde_json::Value =
            serde_json::from_str(&json).expect("valid JSON");
        assert_eq!(parsed["skin"], "android");
        assert_eq!(parsed["device"], 7);
    }

    #[test]
    fn builder_methods_compose() {
        let state_calls = std::rc::Rc::new(std::cell::Cell::new(0u32));
        let counter = state_calls.clone();
        let p = lazy::<DemoProps>(
            DEMO,
            DemoProps {
                skin: "ios".to_string(),
                device: 14,
            },
        )
        .on_state(move |_s| counter.set(counter.get() + 1))
        .placeholder(|| Primitive::View {
            children: Vec::new(),
            style: None,
            ref_fill: None,
            safe_area_sides: crate::SafeAreaSides::NONE,
            on_touch: None,
            accessibility: AccessibilityProps::default(),
            #[cfg(feature = "robot")]
            test_id: None,
        })
        .into_primitive();

        let Primitive::Lazy {
            on_state,
            placeholder,
            ..
        } = p
        else {
            panic!("expected Primitive::Lazy");
        };
        assert!(on_state.is_some(), "on_state should be set");
        assert!(placeholder.is_some(), "placeholder should be set");

        // Driving the on_state hook directly proves the closure is
        // callable in isolation (the walker will invoke it through
        // the same path).
        let cb = on_state.unwrap();
        cb(LazyState::Loading);
        cb(LazyState::Rendered);
        assert_eq!(state_calls.get(), 2);
    }

    #[test]
    fn chunk_id_display_matches_name() {
        let id = ChunkId::new("simulator");
        assert_eq!(id.as_str(), "simulator");
        assert_eq!(format!("{id}"), "simulator");
    }

    #[test]
    fn lazy_state_predicates() {
        assert!(LazyState::Loading.is_loading());
        assert!(LazyState::Loaded.is_loading());
        assert!(!LazyState::Rendered.is_loading());
        assert!(!LazyState::Error("x".into()).is_loading());

        assert!(LazyState::Error("x".into()).is_error());
        assert!(!LazyState::Loading.is_error());
    }
}
